import{_ as i,o as a,c as n,ai as t}from"./chunks/framework.ampVZV4B.js";const d=JSON.parse('{"title":"代理模式与模板方法模式","description":"","frontmatter":{},"headers":[],"relativePath":"design-patterns/proxy-template.md","filePath":"design-patterns/proxy-template.md"}'),l={name:"design-patterns/proxy-template.md"};function e(r,s,p,o,h,g){return a(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="代理模式与模板方法模式" tabindex="-1">代理模式与模板方法模式 <a class="header-anchor" href="#代理模式与模板方法模式" aria-label="Permalink to “代理模式与模板方法模式”">​</a></h1><hr><h3 id="❓-面试官-说一下代理模式-静态代理和动态代理有什么区别-【中级】" tabindex="-1">❓ 面试官：说一下代理模式？静态代理和动态代理有什么区别？【中级】 <a class="header-anchor" href="#❓-面试官-说一下代理模式-静态代理和动态代理有什么区别-【中级】" aria-label="Permalink to “❓ 面试官：说一下代理模式？静态代理和动态代理有什么区别？【中级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 代理模式就是在调用者和目标对象之间<strong>加一层“中介（代理对象）”</strong>。目的是在不修改原目标对象代码的前提下，对它进行<strong>功能增强</strong>（比如加日志、加事务、加权限校验）。</p><p><strong>📝 详细对比实战：</strong></p><p><strong>1. 静态代理（比较笨重，基本不用）</strong></p><ul><li><strong>做法</strong>：由程序员手动写一个代理类，实现跟目标类一样的接口。在代理类的方法里调用目标类的方法，并在前后加上自己的增强逻辑。</li><li><strong>缺点</strong>：如果接口有 100 个方法，代理类就得写 100 遍增强逻辑。如果有 10 个不同的接口需要代理，就得写 10 个代理类。太麻烦了。</li></ul><p><strong>2. 动态代理（框架的基石，极其重要）</strong></p><ul><li><strong>做法</strong>：代理类不需要手写，而是在程序<strong>运行期间，由 JVM 利用反射机制动态生成在内存里</strong>的。</li><li><strong>两大流派（重点必考）</strong>： <ul><li><strong>JDK 动态代理</strong>：Java 自带的。它要求<strong>目标类必须实现了某个接口</strong>。生成的代理类也实现了同样的接口。底层依靠 <code>InvocationHandler</code> 和 <code>Proxy.newProxyInstance</code>。</li><li><strong>CGLIB 动态代理</strong>：第三方库（Spring内置了）。它<strong>不要求目标类实现接口</strong>，只要不是 <code>final</code> 类就行。它的原理是利用 ASM 字节码技术，动态生成一个目标类的<strong>子类</strong>作为代理。</li></ul></li><li><strong>Spring AOP 是用哪种？（连环追问）</strong><ul><li>在 SpringBoot 2.x 以前：如果你的类实现了接口，默认用 JDK；没实现接口，就用 CGLIB。</li><li>在 SpringBoot 2.x 以后：<strong>默认全部使用 CGLIB</strong>（因为 CGLIB 性能更好了，且不需要强迫写接口）。</li></ul></li></ul><hr><h3 id="❓-面试官-你在项目中用过模板方法模式吗-怎么用的-【中级】" tabindex="-1">❓ 面试官：你在项目中用过模板方法模式吗？怎么用的？【中级】 <a class="header-anchor" href="#❓-面试官-你在项目中用过模板方法模式吗-怎么用的-【中级】" aria-label="Permalink to “❓ 面试官：你在项目中用过模板方法模式吗？怎么用的？【中级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 模板方法模式的核心是：<strong>在父类中定义好业务的“骨架流程（模板）”，然后把某些具体的、易变的步骤延迟到子类去实现。</strong></p><p><strong>📝 面试高分实战场景：</strong></p><p>&quot;面试官您好，在我们公司的<strong>文件解析上传模块</strong>中，我大量使用了模板方法模式。&quot;</p><ul><li><p><strong>背景痛点</strong>：我们要处理别人传过来的 Excel、CSV、TXT 各种格式的财务报表。无论是哪种格式，整体的业务流程都是一模一样的：</p><ol><li>验证文件签名和格式。</li><li><strong>解析文件内容（这一步各不相同）</strong>。</li><li>将解析出的数据校验并入库。</li><li>记录操作日志并发送站内信通知。</li></ol></li><li><p><strong>用模板方法重构</strong>：</p><ol><li><strong>建一个抽象父类 <code>AbstractFileHandler</code></strong>，在里面写一个 <code>process()</code> 核心方法。<div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> process</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(File file) {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    verifyFile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(file); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 1. 公共方法：直接在父类写死</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    List&lt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt; dataList </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> parseFile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(file); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 2. 抽象方法：留给子类去实现</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    saveToDb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(dataList); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 3. 公共方法：父类写死</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    sendNotify</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 4. 公共方法：父类写死</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 延迟给子类的抽象方法</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">protected</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> abstract</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> List</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Data</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> parseFile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(File file);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div></li><li><strong>将 <code>process()</code> 方法打上 <code>final</code> 关键字</strong>：非常重要！这是为了防止子类乱改核心骨架流程。</li><li><strong>建具体的子类</strong>：比如 <code>ExcelFileHandler</code> 继承父类，它只需要实现 <code>parseFile()</code> 方法，用 EasyExcel 去解析就行了。其他的校验、入库逻辑它完全不用管。</li></ol></li></ul><p><strong>🌟 为什么这么做（加分项）？</strong> 通过模板方法模式，我们把<strong>不变的行为固化到了父类</strong>中，避免了代码的重复复制；同时把<strong>可变的行为留给了子类</strong>，极其方便日后的扩展。Spring 源码中的 <code>JdbcTemplate</code> 和 <code>RestTemplate</code> 就是极其典型的模板方法模式应用。</p>`,18)])])}const c=i(l,[["render",e]]);export{d as __pageData,c as default};
